let allStories=[];const storiesGrid=document.getElementById('storiesGrid');const emptyState=document.getElementById('emptyState');async function loadManifest(){try{const res=await fetch('/story-manifest.json',{cache:'no-cache'});if(!res.ok)throw new Error();return await res.json();}catch{return null;}}
function renderStories(stories){storiesGrid.innerHTML='';if(!stories.length){emptyState.classList.remove('hidden');return;}
emptyState.classList.add('hidden');stories.forEach(story=>{const dateStr=story.added?new Date(story.added).toLocaleDateString('en-GB',{year:'numeric',month:'short',day:'numeric'}):'';const card=document.createElement('a');card.className='story-card';card.href=`/stories/${story.slug}/`;const coverHtml=story.cover?`<div class="story-card-cover"><img src="/${story.cover}" alt="${story.title}" loading="lazy" /></div>`:'';card.innerHTML=`
      ${coverHtml}
      <div class="story-card-body">
        <div class="story-meta">
          <span class="badge badge-${story.lang}">${story.lang.toUpperCase()}</span>
          ${dateStr ? `<span class="story-date">${dateStr}</span>` : ''}
        </div>
        <h3 class="story-title">${story.title}</h3>
        <p class="story-excerpt">${story.excerpt || ''}</p>
        <span class="story-read-link">Read story →</span>
      </div>`;storiesGrid.appendChild(card);});}
(async()=>{const manifest=await loadManifest();if(!manifest?.stories?.length){emptyState.classList.remove('hidden');return;}
allStories=manifest.stories;renderStories(allStories);})();